const entity = msg.topic;
const state = msg.payload;

let cycle = flow.get("outside_pending_cycle") || null;

function nowIso() {
    return new Date().toISOString();
}

// ─────────────────────────────────────────────
// Normalize HA outside control mode
//
// Purpose:
// - Converts current and legacy Home Assistant control mode names
//   into the short mode values stored in maintenance_log.
// - Keeps DB history consistent after the 2026-07-06 mode rename.
// ─────────────────────────────────────────────
function normalizeMode(controlMode) {
    const mode = String(controlMode || "").trim();

    if (mode === "Auto Fill - Auto Dose" || mode === "Auto") {
        return "auto";
    }

    if (mode === "Manual Fill - Auto Dose" || mode === "Manual") {
        return "manual";
    }

    if (mode === "ESP-Override") {
        return "esp-override";
    }

    return "unknown";
}

function titleForCycle(mode, eventType) {

    if (eventType === "FILL") {
        if (mode === "auto")
            return "🤖 Auto Fill - Auto Dose Complete";

        if (mode === "manual")
            return "🧪 Manual Fill - Auto Dose Complete";

        if (mode === "esp-override")
            return "🟥 ESP-Override Fill Complete";
    }

    // DOSE events
    if (mode === "esp-override")
        return "🟥 ESP-Override Dose Complete";

    if (mode === "auto")
        return "🤖 Auto Maintenance Dose Complete";

    return "🧪 Hydroponics Cycle Complete";
}

function newCycle(eventType) {
    const mode = normalizeMode(msg.control_mode);

    return {
        started_at: nowIso(),

        // Must come from HA control mode, not hardcoded.
        mode: mode,

        // GAL 2026-07-10 ISSUE-006:
        // Auto and Manual cycles wait for post-mixing conductivity capture.
        // ESP-Override actions are intended for immediate logging.
        delay_post_mix_capture: mode !== "esp-override",

        source: "outside",
        location: "patio",
        device: "node_red_cycle_manager",
        event_type: eventType,

        system_gallons: null,
        gallons_added: null,

        dose_a_ml: null,
        dose_b_ml: null,

        // Synchronized conductivity voltage snapshots.
        //
        // A0 = KEYESTUDIO production/control channel
        // A1 = DFRobot validation/reference channel
        //
        // Raw and filtered voltages are stored separately.
        a0_raw_v_before: null,
        a0_filtered_v_before: null,
        a1_raw_v_before: null,
        a1_filtered_v_before: null,

        a0_raw_v_after: null,
        a0_filtered_v_after: null,
        a1_raw_v_after: null,
        a1_filtered_v_after: null,

        fill_used: false,
        pump_a_used: false,
        pump_b_used: false
    };
}

// -----------------------------
// ACTION STARTED
// -----------------------------
if (state === "on") {

    flow.set("outside_cycle_active", true);

    if (entity.includes("water_fill_solenoid")) {
        // Fill starts a fill cycle.
        cycle = newCycle("FILL");
        cycle.fill_used = true;
        msg.capture_before = true;
        node.warn("NEW FILL CYCLE STARTED");
    }

    else if (entity.includes("nutrient_pump_a")) {
        if (!cycle) {
            // Dose-only cycle.
            cycle = newCycle("DOSE");
            msg.capture_before = true;
            node.warn("NEW DOSE CYCLE STARTED");
        } else {
            // Pump A is joining an existing fill cycle.
            node.warn("PUMP A JOINED ACTIVE CYCLE");
        }

        cycle.pump_a_used = true;
    }

    else if (entity.includes("nutrient_pump_b")) {
        if (!cycle) {
            cycle = newCycle("DOSE");
            msg.capture_before = true;
            node.warn("NEW DOSE CYCLE STARTED FROM PUMP B");
        } else {
            node.warn("PUMP B JOINED ACTIVE CYCLE");
        }

        cycle.pump_b_used = true;
    }

    // If water was used, final event is FILL even if dosing also happened.
    if (cycle.fill_used) {
        cycle.event_type = "FILL";
    }

    flow.set("outside_pending_cycle", cycle);
    msg.payload = cycle;
    return msg;
}

// -----------------------------
// ACTION STOPPED
// -----------------------------
if (state === "off") {

    if (!cycle) {
        node.warn("OFF event with no active cycle");
        return null;
    }

    cycle.last_activity = nowIso();

    // GAL 2026-07-10 ISSUE-006:
    // ESP-Override actions are independent events and must be logged
    // immediately after their actual quantity is captured.
    // Auto and Manual cycles wait for post-mixing conductivity capture.
    msg.immediate_log = cycle.delay_post_mix_capture === false;

    // Finalize every ESP-Override action immediately.
    // Auto and Manual cycles finalize when Pump B completes.
    msg.finalize_cycle =
        msg.immediate_log ||
        entity.includes("nutrient_pump_b");

    if (entity.includes("water_fill_solenoid")) {
        msg.capture_fill_done = true;
        node.warn("Fill completed");
    }

    if (entity.includes("nutrient_pump_a")) {
        msg.capture_dose_a_done = true;
        node.warn("Pump A completed");
    }

    if (entity.includes("nutrient_pump_b")) {
        msg.capture_dose_b_done = true;
        node.warn("Pump B completed");
    }

    if (cycle.fill_used) {
        cycle.event_type = "FILL";
    }

    flow.set("outside_pending_cycle", cycle);
    msg.payload = cycle;
    return msg;
}

return null;

// ─────────────────────────────────────────────────────────────
// Save Before Values to Cycle
//
// Responsibility:
//   Copy the synchronized pre-cycle reservoir measurements from
//   msg.event into the persistent outside_pending_cycle object.
//
// Required msg.event inputs:
//   system_gallons
//   a0_raw_v_before
//   a0_filtered_v_before
//   a1_raw_v_before
//   a1_filtered_v_before
//
// Output:
//   msg.payload = Updated outside_pending_cycle object
//
// Revision History:
//
// GAL 2026-07-21
// - Replaced legacy tds_before storage.
// - Added separate A0/A1 raw and filtered pre-cycle voltages.
// - Removed duplicate return statement.
// ─────────────────────────────────────────────────────────────

let cycle =
    flow.get("outside_pending_cycle") || {};

cycle.system_gallons =
    msg.event?.system_gallons ?? null;

cycle.a0_raw_v_before =
    msg.event?.a0_raw_v_before ?? null;

cycle.a0_filtered_v_before =
    msg.event?.a0_filtered_v_before ?? null;

cycle.a1_raw_v_before =
    msg.event?.a1_raw_v_before ?? null;

cycle.a1_filtered_v_before =
    msg.event?.a1_filtered_v_before ?? null;

flow.set(
    "outside_pending_cycle",
    cycle
);

msg.payload = cycle;

return msg;

let cycle = flow.get("outside_pending_cycle") || {};
cycle.gallons_added = msg.event?.gallons_added ?? null;
flow.set("outside_pending_cycle", cycle);
msg.payload = cycle;
return msg;

let cycle = flow.get("outside_pending_cycle") || {};
cycle.dose_a_ml = msg.event?.dose_a_ml ?? null;
flow.set("outside_pending_cycle", cycle);
msg.payload = cycle;
return msg;

let cycle = flow.get("outside_pending_cycle") || {};
cycle.dose_b_ml = msg.event?.dose_b_ml ?? null;
flow.set("outside_pending_cycle", cycle);
msg.payload = cycle;
return msg;

// ─────────────────────────────────────────────────────────────
// Save After Values to Cycle
//
// Responsibility:
//   Add the synchronized post-mixing conductivity measurements to the
//   completed maintenance cycle snapshot.
//
// Uses:
//   msg.completed_cycle
//
// rather than shared flow context so a newer maintenance cycle can begin
// while this completed cycle waits for delayed post-mixing conductivity
// capture and database logging.
//
// Required msg.event inputs:
//   a0_raw_v_after
//   a0_filtered_v_after
//   a1_raw_v_after
//   a1_filtered_v_after
//
// Output:
//   msg.completed_cycle
//
// Revision History:
//
// GAL 2026-07-21
// - Renamed node from "Save TDS After".
// - Replaced legacy tds_after field.
// - Added separate A0/A1 raw and filtered post-mixing voltages.
//
// GAL 2026-07-10 ISSUE-006
// - Original implementation.
// ─────────────────────────────────────────────────────────────

const cycle = msg.completed_cycle;

if (!cycle) {
    node.warn("Missing completed_cycle in Save After Values to Cycle.");
    return null;
}

cycle.a0_raw_v_after =
    msg.event?.a0_raw_v_after ?? null;

cycle.a0_filtered_v_after =
    msg.event?.a0_filtered_v_after ?? null;

cycle.a1_raw_v_after =
    msg.event?.a1_raw_v_after ?? null;

cycle.a1_filtered_v_after =
    msg.event?.a1_filtered_v_after ?? null;

msg.completed_cycle = cycle;
msg.payload = cycle;

return msg;

// ─────────────────────────────────────────────────────────────
// Build Cycle INSERT SQL
//
// Responsibility:
//   Build the maintenance_log INSERT for one completed fill or dose cycle
//   using the isolated snapshot carried in msg.completed_cycle.
//
// Required input:
//   msg.completed_cycle
//
// Outputs:
//   msg.topic   = MariaDB INSERT statement
//   msg.payload = MariaDB INSERT statement
//
// Critical behavior:
//   - Preserves separate A0/A1 raw and filtered before/after voltages.
//   - Uses the completed-cycle snapshot rather than shared flow context.
//   - Missing engineering values are stored as SQL NULL.
//
// Revision History:
//
// GAL 2026-07-21
// - Replaced legacy TDS and A1 voltage field names.
// - Added A0/A1 raw and filtered before/after database fields.
// - Updated the human-readable summary to identify filtered voltage values.
//
// GAL 2026-07-20
// - Added dual conductivity-channel logging.
//
// GAL 2026-07-10 ISSUE-006
// - Isolated completed-cycle logging from the active pending cycle.
// ─────────────────────────────────────────────────────────────

const e = msg.completed_cycle;

if (!e) {
    node.warn(
        "Missing completed_cycle in Build Cycle INSERT SQL."
    );
    return null;
}

/**
 * Safely format optional text for MariaDB.
 *
 * Missing or empty values are stored as SQL NULL.
 * Single quotes are escaped.
 */
function txt(value) {
    if (
        value === undefined ||
        value === null ||
        value === ""
    ) {
        return "NULL";
    }

    return "'" +
        String(value).replace(/'/g, "''") +
        "'";
}

/**
 * Convert a valid numeric value for SQL.
 *
 * Missing, empty, or invalid values are stored as SQL NULL
 * rather than being converted to zero.
 */
function num(value) {
    if (
        value === undefined ||
        value === null ||
        value === ""
    ) {
        return "NULL";
    }

    const numberValue = Number(value);

    return Number.isFinite(numberValue)
        ? String(numberValue)
        : "NULL";
}

/**
 * Format a valid number for human-readable summary text.
 *
 * Returns null when the value is missing or invalid.
 */
function fmtNum(value, decimals) {
    if (
        value === undefined ||
        value === null ||
        value === ""
    ) {
        return null;
    }

    const numberValue = Number(value);

    return Number.isFinite(numberValue)
        ? numberValue.toFixed(decimals)
        : null;
}

/**
 * Add a before/after voltage summary when one or both values exist.
 */
function addVoltageSummary(
    details,
    label,
    beforeValue,
    afterValue
) {
    const before =
        fmtNum(beforeValue, 3);

    const after =
        fmtNum(afterValue, 3);

    if (before !== null && after !== null) {
        details.push(
            `${label} ${before} → ${after} V`
        );
    } else if (before !== null) {
        details.push(
            `${label} before ${before} V`
        );
    } else if (after !== null) {
        details.push(
            `${label} after ${after} V`
        );
    }
}

const mode =
    e.mode || "unknown";

const eventType =
    e.fill_used
        ? "FILL"
        : "DOSE";

const summaryParts = [
    mode,
    eventType
];

const details = [];

const gallonsAdded =
    fmtNum(e.gallons_added, 2);

const doseA =
    fmtNum(e.dose_a_ml, 0);

const doseB =
    fmtNum(e.dose_b_ml, 0);

const systemGallons =
    fmtNum(e.system_gallons, 1);

if (
    gallonsAdded !== null &&
    Number(e.gallons_added) > 0
) {
    details.push(
        `added ${gallonsAdded} gal water`
    );
}

if (
    doseA !== null &&
    Number(e.dose_a_ml) > 0
) {
    details.push(
        `dose A ${doseA} mL`
    );
}

if (
    doseB !== null &&
    Number(e.dose_b_ml) > 0
) {
    details.push(
        `dose B ${doseB} mL`
    );
}

if (systemGallons !== null) {
    details.push(
        `system ${systemGallons} gal`
    );
}

// Use filtered voltages in the concise operator-facing summary.
// Raw values remain preserved in the database and JSON snapshot.
addVoltageSummary(
    details,
    "A0 filtered",
    e.a0_filtered_v_before,
    e.a0_filtered_v_after
);

addVoltageSummary(
    details,
    "A1 filtered",
    e.a1_filtered_v_before,
    e.a1_filtered_v_after
);

const note =
    details.length > 0
        ? `${summaryParts.join(" ")}: ${details.join("; ")}`
        : summaryParts.join(" ");

const raw = {
    ...e,
    final_mode: mode,
    final_event_type: eventType
};

msg.topic = `
INSERT INTO maintenance_log
(
    timestamp_utc,
    internal_time,
    source,
    location,
    device,
    event_type,
    mode,
    system_gallons,
    gallons_added,
    dose_a_ml,
    dose_b_ml,
    a0_raw_v_before,
    a0_filtered_v_before,
    a1_raw_v_before,
    a1_filtered_v_before,
    a0_raw_v_after,
    a0_filtered_v_after,
    a1_raw_v_after,
    a1_filtered_v_after,
    note,
    raw_message
)
VALUES
(
    UTC_TIMESTAMP(),
    NOW(),
    ${txt(e.source)},
    ${txt(e.location)},
    ${txt(e.device)},
    ${txt(eventType)},
    ${txt(mode)},
    ${num(e.system_gallons)},
    ${num(e.gallons_added)},
    ${num(e.dose_a_ml)},
    ${num(e.dose_b_ml)},
    ${num(e.a0_raw_v_before)},
    ${num(e.a0_filtered_v_before)},
    ${num(e.a1_raw_v_before)},
    ${num(e.a1_filtered_v_before)},
    ${num(e.a0_raw_v_after)},
    ${num(e.a0_filtered_v_after)},
    ${num(e.a1_raw_v_after)},
    ${num(e.a1_filtered_v_after)},
    ${txt(note)},
    ${txt(JSON.stringify(raw))}
);
`;

msg.payload = msg.topic;

return msg;

// ─────────────────────────────────────────────────────────────
// Clear Pending Cycle
//
// GAL 2026-07-10 ISSUE-006
//
// Purpose:
// - Marks the completed snapshot as fully logged and notified.
// - Does not clear flow.outside_pending_cycle here because that
//   shared slot was already released before the mixing timer.
// - Prevents this delayed completion path from clearing a newer
//   maintenance cycle that may already be active.
// ─────────────────────────────────────────────────────────────

msg.payload = "cycle logged and notified";
return msg;

// ─────────────────────────────────────────────────────────────
// Build Cycle Completion Notification
//
// Responsibility:
//   Build the user-facing completion notification for one completed
//   hydroponics fill or maintenance-dose cycle.
//
// Required input:
//   msg.completed_cycle
//
// Outputs:
//   msg.title   = Notification title
//   msg.payload = Multi-line notification text
//
// Critical behavior:
//   - Uses the isolated completed-cycle snapshot.
//   - Reports only values relevant to the completed event.
//   - Uses A0 filtered voltage for the concise conductivity summary.
//
// Revision History:
//
// GAL 2026-07-21
// - Replaced legacy tds_before and tds_after references.
// - Renamed the operator-facing measurement from TDS to A0 Filtered.
// - Preserved completed-cycle isolation.
//
// GAL 2026-07-10 ISSUE-006
// - Changed notification source to msg.completed_cycle.
//
// GAL 2026-07-06
// - Updated titles for controller operating modes.
//
// GAL 2026-07-05
// - Distinguished starting and calculated final fill volumes.
//
// GAL 2026-06-30
// - Initial implementation.
// ─────────────────────────────────────────────────────────────

const e = msg.completed_cycle || {};

function fmt(value, decimals = 2) {
    const numberValue = Number(value);

    return Number.isFinite(numberValue)
        ? numberValue.toFixed(decimals)
        : "n/a";
}

function hasNumber(value) {
    return value !== undefined &&
        value !== null &&
        value !== "" &&
        Number.isFinite(Number(value));
}

function titleForCycle(mode, eventType) {
    if (eventType === "FILL") {
        if (mode === "auto") {
            return "🤖 Auto Fill - Auto Dose Complete";
        }

        if (mode === "manual") {
            return "🧪 Manual Fill - Auto Dose Complete";
        }

        if (mode === "esp-override") {
            return "🟥 ESP-Override Fill Complete";
        }
    }

    if (eventType === "DOSE") {
        if (mode === "auto") {
            return "🤖 Auto Maintenance Dose Complete";
        }

        if (mode === "esp-override") {
            return "🟥 ESP-Override Dose Complete";
        }
    }

    return "🧪 Hydroponics Cycle Complete";
}

const mode =
    e.mode || "unknown";

const eventType =
    e.fill_used
        ? "FILL"
        : "DOSE";

const lines = [];

msg.title =
    titleForCycle(mode, eventType);

if (eventType === "FILL") {
    if (mode === "esp-override") {
        lines.push(
            "ESP-Override FILL completed"
        );
    } else if (mode === "manual") {
        lines.push(
            "Manual Fill - Auto Dose cycle completed"
        );
    } else {
        lines.push(
            "Auto Fill - Auto Dose cycle completed"
        );
    }
}

if (Number(e.gallons_added) > 0) {
    lines.push(
        `Water Added: ${fmt(e.gallons_added)} gal`
    );
}

if (Number(e.dose_a_ml) > 0) {
    lines.push(
        `Dose A: ${fmt(e.dose_a_ml, 0)} mL`
    );
}

if (Number(e.dose_b_ml) > 0) {
    lines.push(
        `Dose B: ${fmt(e.dose_b_ml, 0)} mL`
    );
}

if (eventType === "FILL") {
    lines.push(
        `Starting Volume: ${fmt(e.system_gallons, 1)} gal`
    );

    const calculatedFinal =
        Number(e.system_gallons) +
        Number(e.gallons_added);

    if (Number.isFinite(calculatedFinal)) {
        lines.push(
            `Calculated Final Volume: ${fmt(calculatedFinal, 1)} gal`
        );
    }
} else {
    lines.push(
        `System Volume: ${fmt(e.system_gallons, 1)} gal`
    );
}

if (
    hasNumber(e.a0_filtered_v_before) &&
    hasNumber(e.a0_filtered_v_after)
) {
    lines.push(
        `A0 Filtered: ` +
        `${fmt(e.a0_filtered_v_before, 3)} → ` +
        `${fmt(e.a0_filtered_v_after, 3)} V`
    );
} else if (hasNumber(e.a0_filtered_v_before)) {
    lines.push(
        `A0 Filtered Before: ` +
        `${fmt(e.a0_filtered_v_before, 3)} V`
    );
} else if (hasNumber(e.a0_filtered_v_after)) {
    lines.push(
        `A0 Filtered After: ` +
        `${fmt(e.a0_filtered_v_after, 3)} V`
    );
}

msg.payload =
    lines.join("\n");

return msg;

// ─────────────────────────────────────────────────────────────
// Snapshot Completed Cycle
//
// GAL 2026-07-10 ISSUE-006
//
// Purpose:
// - Copies one completed physical fill or dose event into the message.
// - Immediately releases the shared active-cycle slot.
// - Allows the next hardware event to start as a separate DB record.
// - Automatic cycles may continue through the post-mixing
//   conductivity capture path.
// - ESP-Override events may proceed directly to database logging.
// ─────────────────────────────────────────────────────────────

const cycle = flow.get("outside_pending_cycle");

if (!cycle) {
    node.warn("Cannot snapshot completed cycle: no pending cycle.");
    return null;
}

// Preserve this completed cycle independently of flow context.
msg.completed_cycle = JSON.parse(JSON.stringify(cycle));

// Release the shared cycle immediately.
flow.set("outside_pending_cycle", null);
flow.set("outside_cycle_active", false);

// Give each completed cycle an independent mixing timer.
msg.topic = msg.completed_cycle.started_at;

return msg;
